UPDATE ESG.TB_NEAR_MISS_REPORT
SET
    USE_YN = 'N',
    UPDATED_AT = now(),
    UPDATED_BY = #{updatedBy}
WHERE DOC_NO = #{docNo} AND WRITE_YEAR = #{writeYear}

mapper.select:
SELECT WRITE_YEAR, DOC_TYPE, DOC_NO, COMP_ID, CAR_TYPE, TITLE, CTRL_ORGN_ID, CTRL_ORGN_NM, ACTION_ORGN_ID, ACTION_ORGN_NM, WRITE_DT, RETURN_DT, ACTION_REQUEST_CONTENT, ANALYTIC_PREVENT_CONTENT, RESULT_VALIDATION_CONTENT, RESULT_VALIDATION_YN, CHECK_DT, USE_YN, CREATED_AT, CREATED_BY, UPDATED_AT, UPDATED_BY FROM ESG.TB_CORRECTIVE_ACTION_REQUEST WHERE 1=1 AND CAR_TYPE='I'
AND WRITE_YEAR = #{writeYear}
AND COMP_ID = #{compId}
ORDER BY CTRL_ORGN_ID, CASE WHEN USE_YN = 'Y' THEN 1 ELSE 2 END, DOC_NO DESC

