        UPDATE ESG.TB_CORRECTIVE_ACTION_REQUEST
        SET
            USE_YN 			='N',
            UPDATED_AT 		=NOW(),
            UPDATED_BY 		=#{updatedBy}
        WHERE 1=1
        	AND WRITE_YEAR	=#{writeYear}
			AND DOC_NO		=#{docNo}
