mapper.select:
SELECT tirs.doc_seq, tirs.statement_type, write_dt, tirs.statement_content, case when tai.target_id is null then 'I' else 'U' end as target_id FROM esg.tb_incident_report_statement tirs left join esg.tb_approval_info tai on tai.target_id =#{writeYear} || #{docNo} and tai.target_type ='ICR' and tai.type = #{type} where doc_no=#{docNo} and write_year=#{writeYear} and statement_type=#{statementType}
UNION ALL
SELECT '' AS doc_seq, '' AS statement_type, to_char(now(),'YYYYMMDD') AS write_dt, '' AS statement_content, case when (select 1 from esg.tb_approval_info tai where tai.target_id = #{writeYear} || #{docNo} and tai.type = #{type}) is null then 'I' else 'U' end as target_id WHERE NOT EXISTS ( SELECT 1 FROM esg.tb_incident_report_statement tirs left join esg.tb_approval_info tai on tai.target_id = #{writeYear} || #{docNo} and tai.target_type ='ICR' where doc_no = #{docNo} and write_year = #{writeYear} and statement_type = #{statementType});

mapper.update:
    	UPDATE esg.tb_incident_report_Statement
			SET  
			write_dt= #{writeDt}, 
			statement_content=#{statementContent}, 
			updated_at=now(), 
			updated_by=#{updatedBy}
		WHERE 
			write_year=#{writeYear} 
			AND doc_type='ICR' 
			AND doc_no=#{docNo} 
			AND doc_seq=#{docSeq} 
			and statement_type=#{statementType}

